class Solution {
public:
    int findUnsortedSubarray(vector<int>& nums) {
        int n = nums.size();
        vector<int> sorted_nums = nums;
        sort(sorted_nums.begin(), sorted_nums.end());
        int start = n, end = 0;
        for (int i = 0; i < n; i++) {
            if (nums[i] != sorted_nums[i]) {
                start = min(start, i);
                end = max(end, i);
            }
        }
        return end - start >= 0 ? end - start + 1 : 0;
    }
};
